+@page "/board"
+@using sv_7942bd189ea54c95880bb7fd007d7b2d.Services
+@inject ITaskService TaskService
+@rendermode InteractiveServer
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h2 class="mb-3">Project Board</h2>
+
+@if (isLoading)
+{
+    <div class="d-flex justify-content-center my-5">
+        <div class="spinner-border text-primary" role="status">
+            <span class="visually-hidden">Loading...</span>
+        </div>
+    </div>
+}
+else if (errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error:</strong> @errorMessage
+        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
+    </div>
+}
+else
+{
+    <!-- Stats Bar -->
+    <div class="stats-bar d-flex flex-wrap gap-3 mb-3">
+        <span class="badge bg-secondary">Total: @allTasks.Count</span>
+        <span class="badge bg-info text-dark">To Do: @GetColumnTasks("To Do").Count</span>
+        <span class="badge bg-warning text-dark">In Progress: @GetColumnTasks("In Progress").Count</span>
+        <span class="badge bg-success">Done: @GetColumnTasks("Done").Count</span>
+        <span class="badge bg-danger">Overdue: @allTasks.Count(t => t.DueDate.Date < DateTime.Today && t.Status != "Done")</span>
+    </div>
+
+    <!-- Search Bar -->
+    <div class="mb-3">
+        <input type="text" class="form-control" placeholder="Search tasks by title..."
+               @bind="searchText" @bind:event="oninput" />
+    </div>
+
+    <!-- Kanban Columns -->
+    <div class="row g-3">
+        @foreach (var column in columns)
+        {
+            var colTasks = GetFilteredColumnTasks(column);
+            var colIndex = Array.IndexOf(columns, column);
+
+            <div class="col-md-4">
+                <div class="card kanban-column">
+                    <div class="card-header d-flex justify-content-between align-items-center">
+                        <strong>@column</strong>
+                        <span class="badge bg-dark">@colTasks.Count</span>
+                    </div>
+                    <div class="card-body kanban-body">
+                        @foreach (var task in colTasks)
+                        {
+                            var taskCapture = task;
+                            var colIndexCapture = colIndex;
+
+                            <div class="card task-card mb-2">
+                                <div class="card-body p-2">
+                                    <h6 class="card-title mb-1">@taskCapture.Title</h6>
+                                    <p class="card-text mb-1 text-muted small">@taskCapture.Assignee</p>
+                                    <div class="d-flex justify-content-between align-items-center mb-1">
+                                        <span class="badge priority-@taskCapture.Priority.ToLowerInvariant()">
+                                            @taskCapture.Priority
+                                        </span>
+                                        <small class="text-muted">@taskCapture.DueDate.ToString("MMM dd")</small>
+                                    </div>
+                                    <div class="d-flex gap-1">
+                                        @if (colIndexCapture > 0)
+                                        {
+                                            <button class="btn btn-sm btn-outline-secondary"
+                                                    disabled="@isMoving"
+                                                    @onclick="() => MoveTaskAsync(taskCapture.Id, columns[colIndexCapture - 1])">
+                                                &larr; Move Left
+                                            </button>
+                                        }
+                                        @if (colIndexCapture < columns.Length - 1)
+                                        {
+                                            <button class="btn btn-sm btn-outline-secondary"
+                                                    disabled="@isMoving"
+                                                    @onclick="() => MoveTaskAsync(taskCapture.Id, columns[colIndexCapture + 1])">
+                                                Move Right &rarr;
+                                            </button>
+                                        }
+                                    </div>
+                                </div>
+                            </div>
+                        }
+
+                        @if (addingToColumn == column)
+                        {
+                            <div class="card border-primary mb-2">
+                                <div class="card-body p-2">
+                                    <div class="mb-2">
+                                        <input type="text" class="form-control form-control-sm" placeholder="Title"
+                                               @bind="newTitle" />
+                                    </div>
+                                    <div class="mb-2">
+                                        <input type="text" class="form-control form-control-sm" placeholder="Assignee"
+                                               @bind="newAssignee" />
+                                    </div>
+                                    <div class="mb-2">
+                                        <select class="form-select form-select-sm" @bind="newPriority">
+                                            <option value="High">High</option>
+                                            <option value="Medium">Medium</option>
+                                            <option value="Low">Low</option>
+                                        </select>
+                                    </div>
+                                    <div class="mb-2">
+                                        <input type="date" class="form-control form-control-sm"
+                                               @bind="newDueDate" />
+                                    </div>
+                                    <div class="d-flex gap-1">
+                                        <button class="btn btn-sm btn-primary" disabled="@isSaving"
+                                                @onclick="() => SaveTaskAsync(column)">
+                                            @(isSaving ? "Saving..." : "Save")
+                                        </button>
+                                        <button class="btn btn-sm btn-outline-secondary" disabled="@isSaving"
+                                                @onclick="CancelAdd">Cancel</button>
+                                    </div>
+                                </div>
+                            </div>
+                        }
+                    </div>
+                    <div class="card-footer">
+                        <button class="btn btn-sm btn-outline-primary w-100"
+                                @onclick="() => StartAdd(column)">
+                            + Add Task
+                        </button>
+                    </div>
+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private readonly string[] columns = ["To Do", "In Progress", "Done"];
+
+    private List<TaskItem> allTasks = new();
+    private bool isLoading = true;
+    private bool isMoving;
+    private bool isSaving;
+    private string? errorMessage;
+    private string searchText = string.Empty;
+
+    // Add-task form state
+    private string? addingToColumn;
+    private string newTitle = string.Empty;
+    private string newAssignee = string.Empty;
+    private string newPriority = "Medium";
+    private DateTime newDueDate = DateTime.Today.AddDays(7);
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasksAsync();
+    }
+
+    private async Task LoadTasksAsync()
+    {
+        isLoading = true;
+        errorMessage = null;
+        try
+        {
+            allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isLoading = false;
+        }
+    }
+
+    private List<TaskItem> GetColumnTasks(string status)
+        => allTasks.Where(t => t.Status == status).ToList();
+
+    private List<TaskItem> GetFilteredColumnTasks(string status)
+    {
+        var tasks = allTasks.Where(t => t.Status == status);
+        if (!string.IsNullOrWhiteSpace(searchText))
+        {
+            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
+        }
+        return tasks.ToList();
+    }
+
+    private async Task MoveTaskAsync(int taskId, string newStatus)
+    {
+        isMoving = true;
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var idx = allTasks.FindIndex(t => t.Id == taskId);
+            if (idx >= 0)
+            {
+                allTasks[idx] = allTasks[idx] with { Status = newStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isMoving = false;
+        }
+    }
+
+    private void StartAdd(string column)
+    {
+        addingToColumn = column;
+        newTitle = string.Empty;
+        newAssignee = string.Empty;
+        newPriority = "Medium";
+        newDueDate = DateTime.Today.AddDays(7);
+    }
+
+    private void CancelAdd()
+    {
+        addingToColumn = null;
+    }
+
+    private async Task SaveTaskAsync(string column)
+    {
+        if (string.IsNullOrWhiteSpace(newTitle))
+            return;
+
+        isSaving = true;
+        try
+        {
+            var created = await TaskService.CreateTaskAsync(newTitle.Trim(), newAssignee.Trim(), newPriority, newDueDate);
+            // If the task was created in a column other than its default status, update it
+            if (created.Status != column)
+            {
+                await TaskService.UpdateTaskStatusAsync(created.Id, column);
+                created = created with { Status = column };
+            }
+            allTasks.Add(created);
+            addingToColumn = null;
+        }
+        catch (Exception ex)
+        {
+            errorMessage = ex.Message;
+        }
+        finally
+        {
+            isSaving = false;
+        }
+    }
+}
+

