    font-size: 0.9rem;
    padding: 0.5em 0.75em;
}

::deep .priority-high {
    background-color: #dc3545;
    color: #fff;
}

::deep .priority-medium {
    background-color: #ffc107;
    color: #212529;
}

::deep .priority-low {
    background-color: #198754;
    color: #fff;
}

